import React, { useState, useRef, useEffect, useCallback } from 'react';

// ============================================================================
// ECLISSI — Swipeable App Shell
// Dashboard (center) ← Voice Chat (left) | AI-BRARIAN (right) →
// ============================================================================

const Eclissi = () => {
  // ──────────────────────────────────────────────────────────────────────────
  // NAVIGATION STATE
  // ──────────────────────────────────────────────────────────────────────────
  const [currentPage, setCurrentPage] = useState(1); // 0=Voice, 1=Dashboard, 2=Library
  const [isDragging, setIsDragging] = useState(false);
  const [dragOffset, setDragOffset] = useState(0);
  const [startX, setStartX] = useState(0);
  const containerRef = useRef(null);

  const pages = [
    { id: 'voice', label: 'Luna', icon: '🌙' },
    { id: 'dashboard', label: 'Home', icon: '⬡' },
    { id: 'library', label: 'Library', icon: '📚' },
  ];

  // ──────────────────────────────────────────────────────────────────────────
  // SHARED STATE
  // ──────────────────────────────────────────────────────────────────────────
  const [systemStatus, setSystemStatus] = useState({
    daemon: 'running',
    llm: 'claude',
    voiceActive: true,
  });

  const [librarySources, setLibrarySources] = useState([
    { id: 1, name: 'mars-college', status: 'active', files: 21, chunks: 147, size: 2.4 },
    { id: 2, name: 'research-papers', status: 'syncing', files: 45, chunks: 312, size: 8.1, progress: 67 },
    { id: 3, name: 'project-archive', status: 'disconnected', files: 0, chunks: 0, size: 0 },
  ]);

  const [memoryStats] = useState({
    nodes: 1247,
    edges: 3891,
    sessions: 42,
  });

  // ──────────────────────────────────────────────────────────────────────────
  // SWIPE HANDLERS
  // ──────────────────────────────────────────────────────────────────────────
  const handleDragStart = (clientX) => {
    setIsDragging(true);
    setStartX(clientX);
  };

  const handleDragMove = (clientX) => {
    if (!isDragging) return;
    const diff = clientX - startX;
    setDragOffset(diff);
  };

  const handleDragEnd = () => {
    if (!isDragging) return;
    setIsDragging(false);

    const threshold = 100;
    if (dragOffset > threshold && currentPage > 0) {
      setCurrentPage(currentPage - 1);
    } else if (dragOffset < -threshold && currentPage < pages.length - 1) {
      setCurrentPage(currentPage + 1);
    }
    setDragOffset(0);
  };

  // Mouse events
  const onMouseDown = (e) => handleDragStart(e.clientX);
  const onMouseMove = (e) => handleDragMove(e.clientX);
  const onMouseUp = () => handleDragEnd();
  const onMouseLeave = () => handleDragEnd();

  // Touch events
  const onTouchStart = (e) => handleDragStart(e.touches[0].clientX);
  const onTouchMove = (e) => handleDragMove(e.touches[0].clientX);
  const onTouchEnd = () => handleDragEnd();

  // Keyboard navigation
  useEffect(() => {
    const handleKeyDown = (e) => {
      if (e.key === 'ArrowLeft' && currentPage > 0) {
        setCurrentPage(currentPage - 1);
      } else if (e.key === 'ArrowRight' && currentPage < pages.length - 1) {
        setCurrentPage(currentPage + 1);
      }
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [currentPage]);

  // ──────────────────────────────────────────────────────────────────────────
  // SHARED COMPONENTS
  // ──────────────────────────────────────────────────────────────────────────
  const GradientOrb = ({ className, color1, color2, delay = 0 }) => (
    <div 
      className={`absolute rounded-full blur-3xl opacity-15 pointer-events-none ${className}`}
      style={{
        background: `radial-gradient(circle, ${color1} 0%, ${color2} 50%, transparent 70%)`,
        animation: `pulse 8s ease-in-out infinite`,
        animationDelay: `${delay}s`,
      }}
    />
  );

  const GlassCard = ({ children, className = '', onClick, hover = true }) => (
    <div 
      onClick={onClick}
      className={`
        backdrop-blur-xl bg-white/5 border border-white/10 rounded-2xl
        ${hover ? 'hover:bg-white/[0.08] hover:border-white/20 cursor-pointer' : ''}
        transition-all duration-300 ${className}
      `}
    >
      {children}
    </div>
  );

  const StatusDot = ({ status, pulse = false }) => {
    const colors = {
      running: 'bg-emerald-400 shadow-emerald-400/50',
      active: 'bg-emerald-400 shadow-emerald-400/50',
      syncing: 'bg-sky-400 shadow-sky-400/50',
      disconnected: 'bg-amber-400 shadow-amber-400/50',
      error: 'bg-red-400 shadow-red-400/50',
    };
    return (
      <div className={`w-2 h-2 rounded-full shadow-lg ${colors[status]} ${pulse ? 'animate-pulse' : ''}`} />
    );
  };

  // ──────────────────────────────────────────────────────────────────────────
  // PAGE: DASHBOARD (Center)
  // ──────────────────────────────────────────────────────────────────────────
  const DashboardPage = () => (
    <div className="min-h-screen p-6 flex flex-col">
      {/* Header */}
      <div className="text-center mb-8 pt-8">
        <div className="inline-flex items-center gap-2 px-4 py-2 rounded-full bg-white/5 border border-white/10 mb-4">
          <StatusDot status={systemStatus.daemon} pulse />
          <span className="text-white/70 text-sm">Eclissi Hub</span>
        </div>
        <h1 className="text-3xl font-light text-white/90 mb-2">Welcome back</h1>
        <p className="text-white/40 text-sm">Luna is online and ready</p>
      </div>

      {/* Quick Stats */}
      <div className="grid grid-cols-3 gap-3 mb-6">
        {[
          { label: 'Nodes', value: memoryStats.nodes.toLocaleString(), color: 'text-violet-400' },
          { label: 'Sources', value: librarySources.length, color: 'text-cyan-400' },
          { label: 'Sessions', value: memoryStats.sessions, color: 'text-emerald-400' },
        ].map((stat, i) => (
          <GlassCard key={i} hover={false} className="p-4 text-center">
            <div className={`text-2xl font-light ${stat.color}`}>{stat.value}</div>
            <div className="text-[10px] text-white/40 tracking-widest uppercase mt-1">{stat.label}</div>
          </GlassCard>
        ))}
      </div>

      {/* Navigation Cards */}
      <div className="flex-1 grid grid-cols-2 gap-4">
        {/* Luna Voice */}
        <GlassCard 
          onClick={() => setCurrentPage(0)}
          className="p-6 flex flex-col items-center justify-center text-center"
        >
          <div 
            className="w-16 h-16 rounded-full mb-4"
            style={{
              background: 'radial-gradient(circle at 30% 30%, #c4b5fd 0%, #a78bfa 30%, #7c3aed 60%, #4c1d95 100%)',
              boxShadow: '0 0 40px rgba(167, 139, 250, 0.3)',
            }}
          />
          <div className="text-white/90 font-medium mb-1">Luna</div>
          <div className="text-white/40 text-xs">Voice Chat</div>
          <div className="flex items-center gap-1 mt-3 text-emerald-400 text-xs">
            <StatusDot status="active" />
            <span>Active</span>
          </div>
        </GlassCard>

        {/* AI-BRARIAN */}
        <GlassCard 
          onClick={() => setCurrentPage(2)}
          className="p-6 flex flex-col items-center justify-center text-center"
        >
          <div className="text-4xl mb-4">📚</div>
          <div className="text-white/90 font-medium mb-1">AI-BRARIAN</div>
          <div className="text-white/40 text-xs">Library Sync</div>
          <div className="flex items-center gap-1 mt-3 text-sky-400 text-xs">
            <StatusDot status="syncing" />
            <span>1 syncing</span>
          </div>
        </GlassCard>
      </div>

      {/* System Status Footer */}
      <div className="mt-6 pt-4 border-t border-white/5">
        <div className="flex items-center justify-between text-xs text-white/30">
          <div className="flex items-center gap-4">
            <div className="flex items-center gap-2">
              <StatusDot status="running" pulse />
              <span>Daemon</span>
            </div>
            <span className="text-white/10">|</span>
            <span>LLM: <span className="text-violet-400">{systemStatus.llm}</span></span>
          </div>
          <span className="text-white/20">← swipe →</span>
        </div>
      </div>
    </div>
  );

  // ──────────────────────────────────────────────────────────────────────────
  // PAGE: LUNA VOICE (Left)
  // ──────────────────────────────────────────────────────────────────────────
  const [lunaText, setLunaText] = useState(['Hey there', 'What\'s on your mind?']);
  const [lunaPosition, setLunaPosition] = useState({ x: 50, y: 45 });
  const [voiceMessages, setVoiceMessages] = useState([
    { from: 'user', text: 'Hey Luna, what\'s the status on everything?' },
  ]);

  // Simple Luna drift
  useEffect(() => {
    if (currentPage !== 0) return;
    const interval = setInterval(() => {
      setLunaPosition(prev => ({
        x: 50 + Math.sin(Date.now() / 3000) * 5,
        y: 45 + Math.cos(Date.now() / 2500) * 3,
      }));
    }, 50);
    return () => clearInterval(interval);
  }, [currentPage]);

  const VoicePage = () => (
    <div className="min-h-screen relative overflow-hidden">
      {/* Status Header */}
      <div className="absolute top-4 left-1/2 -translate-x-1/2 z-50">
        <div className="flex items-center gap-2 px-4 py-2 rounded-full bg-white/5 backdrop-blur-xl border border-white/10">
          <div className="w-2 h-2 rounded-full bg-emerald-400 animate-pulse" />
          <span className="text-white/70 text-sm">Luna</span>
          <span className="text-white/30">•</span>
          <span className="text-white/50 text-sm">Voice Active</span>
        </div>
      </div>

      {/* Dialogue Messages */}
      <div className="absolute top-20 right-4 w-72 space-y-2 z-20">
        {voiceMessages.slice(-3).map((msg, i) => (
          <div 
            key={i}
            className="px-4 py-3 rounded-2xl bg-slate-800/80 backdrop-blur-xl border border-slate-700/50"
            style={{ opacity: 1 - (voiceMessages.length - 1 - i) * 0.2 }}
          >
            <p className="text-white/80 text-sm">{msg.text}</p>
          </div>
        ))}
      </div>

      {/* Luna Orb */}
      <div 
        className="absolute z-30 transition-all duration-300"
        style={{
          left: `${lunaPosition.x}%`,
          top: `${lunaPosition.y}%`,
          transform: 'translate(-50%, -50%)',
        }}
      >
        {/* Golden text */}
        <div className="absolute bottom-full left-1/2 -translate-x-1/2 mb-4 text-center whitespace-nowrap">
          {lunaText.map((line, i) => (
            <div 
              key={i}
              className="text-xl font-light"
              style={{ color: '#d4a574', textShadow: '0 0 20px rgba(212, 165, 116, 0.3)' }}
            >
              {line}
            </div>
          ))}
        </div>

        {/* Orb */}
        <div 
          className="w-24 h-24 rounded-full"
          style={{
            background: 'radial-gradient(circle at 30% 30%, #c4b5fd 0%, #a78bfa 30%, #7c3aed 60%, #4c1d95 100%)',
            boxShadow: '0 0 60px rgba(167, 139, 250, 0.4), 0 0 100px rgba(124, 58, 237, 0.2)',
            animation: 'breathe 4s ease-in-out infinite',
          }}
        >
          <div 
            className="absolute inset-2 rounded-full"
            style={{ background: 'radial-gradient(circle at 40% 40%, rgba(255,255,255,0.3) 0%, transparent 50%)' }}
          />
        </div>
      </div>

      {/* Sample Module (like in screenshots) */}
      <div className="absolute left-4 top-1/3 w-56 backdrop-blur-xl bg-white/5 border border-white/10 rounded-2xl z-10">
        <div className="px-4 py-3 border-b border-white/5">
          <div className="flex items-center gap-2">
            <span>📚</span>
            <span className="text-xs font-medium tracking-widest uppercase text-white/50">LIBRARY</span>
          </div>
        </div>
        <div className="p-3 space-y-1">
          {librarySources.slice(0, 2).map((s) => (
            <div key={s.id} className="flex items-start gap-2 p-2">
              <div className={`w-0.5 h-8 rounded-full ${s.status === 'active' ? 'bg-emerald-400' : 'bg-sky-400 animate-pulse'}`} />
              <div>
                <div className="text-white/90 text-sm font-medium">{s.name}</div>
                <div className="text-white/40 text-xs">{s.status === 'syncing' ? 'Syncing...' : `${s.chunks} chunks`}</div>
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Swipe hint */}
      <div className="absolute bottom-6 left-1/2 -translate-x-1/2 text-white/20 text-xs">
        swipe right for home →
      </div>
    </div>
  );

  // ──────────────────────────────────────────────────────────────────────────
  // PAGE: AI-BRARIAN (Right)
  // ──────────────────────────────────────────────────────────────────────────
  const [selectedSource, setSelectedSource] = useState(null);

  const syncSource = (id) => {
    setLibrarySources(prev => prev.map(s => 
      s.id === id ? { ...s, status: 'syncing', progress: 0 } : s
    ));

    let progress = 0;
    const interval = setInterval(() => {
      progress += Math.random() * 20 + 5;
      if (progress >= 100) {
        clearInterval(interval);
        setLibrarySources(prev => prev.map(s => 
          s.id === id ? { ...s, status: 'active', progress: 100, chunks: s.chunks + 15 } : s
        ));
      } else {
        setLibrarySources(prev => prev.map(s => 
          s.id === id ? { ...s, progress: Math.min(progress, 99) } : s
        ));
      }
    }, 200);
  };

  const LibraryPage = () => (
    <div className="min-h-screen p-6">
      {/* Header */}
      <div className="mb-6 pt-4">
        <div className="flex items-center gap-3 mb-2">
          <div className="w-1 h-8 bg-gradient-to-b from-violet-400 to-cyan-400 rounded-full" />
          <h1 className="text-2xl font-light text-white/90">AI-BRARIAN</h1>
        </div>
        <p className="text-white/40 text-sm ml-4">Library synchronization</p>
      </div>

      {/* Stats Row */}
      <div className="grid grid-cols-4 gap-2 mb-6">
        {[
          { label: 'Sources', value: librarySources.length },
          { label: 'Files', value: librarySources.reduce((s, src) => s + src.files, 0) },
          { label: 'Chunks', value: librarySources.reduce((s, src) => s + src.chunks, 0) },
          { label: 'Size', value: `${librarySources.reduce((s, src) => s + src.size, 0).toFixed(1)}MB` },
        ].map((stat, i) => (
          <GlassCard key={i} hover={false} className="p-3 text-center">
            <div className="text-lg font-light text-white/90">{stat.value}</div>
            <div className="text-[9px] text-white/40 tracking-widest uppercase">{stat.label}</div>
          </GlassCard>
        ))}
      </div>

      {/* Source List */}
      <div className="space-y-3">
        {librarySources.map((source) => (
          <GlassCard 
            key={source.id} 
            className="p-4"
            onClick={() => setSelectedSource(source.id === selectedSource ? null : source.id)}
          >
            <div className="flex items-center justify-between">
              <div className="flex items-center gap-3">
                <StatusDot status={source.status} pulse={source.status === 'syncing'} />
                <div>
                  <div className="text-white/90 font-medium">{source.name}</div>
                  <div className="text-xs text-white/40">
                    {source.files} files • {source.chunks} chunks
                  </div>
                </div>
              </div>

              <div className="flex items-center gap-3">
                {source.status === 'syncing' && (
                  <div className="flex items-center gap-2">
                    <div className="w-16 h-1 bg-white/10 rounded-full overflow-hidden">
                      <div 
                        className="h-full bg-gradient-to-r from-violet-400 to-cyan-400 rounded-full transition-all"
                        style={{ width: `${source.progress || 0}%` }}
                      />
                    </div>
                    <span className="text-xs text-white/40">{Math.floor(source.progress || 0)}%</span>
                  </div>
                )}

                <button 
                  onClick={(e) => {
                    e.stopPropagation();
                    if (source.status !== 'syncing') syncSource(source.id);
                  }}
                  disabled={source.status === 'syncing'}
                  className="w-8 h-8 rounded-lg bg-white/5 border border-white/10 flex items-center justify-center text-white/50 hover:bg-white/10 disabled:opacity-30 transition-all"
                >
                  <svg className={`w-4 h-4 ${source.status === 'syncing' ? 'animate-spin' : ''}`} fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
                  </svg>
                </button>
              </div>
            </div>

            {/* Expanded details */}
            {selectedSource === source.id && (
              <div className="mt-4 pt-4 border-t border-white/5 grid grid-cols-2 gap-4">
                <div>
                  <div className="text-xs text-white/40 mb-1">Path</div>
                  <div className="text-sm text-white/60 font-mono">/{source.name}</div>
                </div>
                <div>
                  <div className="text-xs text-white/40 mb-1">Size</div>
                  <div className="text-sm text-white/60">{source.size} MB</div>
                </div>
              </div>
            )}
          </GlassCard>
        ))}

        {/* Add Source */}
        <GlassCard className="p-4 border-dashed border-white/10">
          <div className="flex items-center justify-center gap-2 text-white/30">
            <span className="text-lg">+</span>
            <span className="text-sm">Add Source</span>
          </div>
        </GlassCard>
      </div>

      {/* Swipe hint */}
      <div className="mt-6 text-center text-white/20 text-xs">
        ← swipe left for home
      </div>
    </div>
  );

  // ──────────────────────────────────────────────────────────────────────────
  // NAV INDICATORS
  // ──────────────────────────────────────────────────────────────────────────
  const NavArrow = ({ direction, onClick, visible }) => (
    <button
      onClick={onClick}
      className={`
        fixed top-1/2 -translate-y-1/2 z-50
        w-10 h-20 flex items-center justify-center
        text-white/20 hover:text-white/50 transition-all
        ${direction === 'left' ? 'left-0' : 'right-0'}
        ${visible ? 'opacity-100' : 'opacity-0 pointer-events-none'}
      `}
    >
      <svg className="w-6 h-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
        <path 
          strokeLinecap="round" 
          strokeLinejoin="round" 
          strokeWidth={1.5} 
          d={direction === 'left' ? 'M15 19l-7-7 7-7' : 'M9 5l7 7-7 7'} 
        />
      </svg>
    </button>
  );

  const PageDots = () => (
    <div className="fixed bottom-4 left-1/2 -translate-x-1/2 z-50 flex items-center gap-2">
      {pages.map((page, i) => (
        <button
          key={page.id}
          onClick={() => setCurrentPage(i)}
          className={`
            transition-all duration-300
            ${currentPage === i 
              ? 'w-6 h-2 rounded-full bg-white/50' 
              : 'w-2 h-2 rounded-full bg-white/20 hover:bg-white/30'
            }
          `}
        />
      ))}
    </div>
  );

  // ──────────────────────────────────────────────────────────────────────────
  // RENDER
  // ──────────────────────────────────────────────────────────────────────────
  const translateX = -currentPage * 100 + (isDragging ? (dragOffset / window.innerWidth) * 100 : 0);

  return (
    <div className="fixed inset-0 bg-black overflow-hidden">
      {/* Background Orbs */}
      <GradientOrb className="w-[600px] h-[600px] -top-40 -left-40" color1="#8b5cf6" color2="#3b82f6" />
      <GradientOrb className="w-[500px] h-[500px] top-1/2 -right-32" color1="#06b6d4" color2="#8b5cf6" delay={3} />
      <GradientOrb className="w-[400px] h-[400px] -bottom-32 left-1/3" color1="#ec4899" color2="#8b5cf6" delay={6} />

      {/* Swipeable Container */}
      <div
        ref={containerRef}
        className="h-full flex touch-pan-y"
        style={{
          width: `${pages.length * 100}%`,
          transform: `translateX(${translateX}%)`,
          transition: isDragging ? 'none' : 'transform 0.4s cubic-bezier(0.16, 1, 0.3, 1)',
        }}
        onMouseDown={onMouseDown}
        onMouseMove={onMouseMove}
        onMouseUp={onMouseUp}
        onMouseLeave={onMouseLeave}
        onTouchStart={onTouchStart}
        onTouchMove={onTouchMove}
        onTouchEnd={onTouchEnd}
      >
        {/* Page: Voice */}
        <div className="w-full h-full flex-shrink-0" style={{ width: `${100 / pages.length}%` }}>
          <VoicePage />
        </div>

        {/* Page: Dashboard */}
        <div className="w-full h-full flex-shrink-0" style={{ width: `${100 / pages.length}%` }}>
          <DashboardPage />
        </div>

        {/* Page: Library */}
        <div className="w-full h-full flex-shrink-0" style={{ width: `${100 / pages.length}%` }}>
          <LibraryPage />
        </div>
      </div>

      {/* Navigation */}
      <NavArrow direction="left" onClick={() => setCurrentPage(Math.max(0, currentPage - 1))} visible={currentPage > 0} />
      <NavArrow direction="right" onClick={() => setCurrentPage(Math.min(pages.length - 1, currentPage + 1))} visible={currentPage < pages.length - 1} />
      <PageDots />

      {/* Styles */}
      <style>{`
        @keyframes pulse {
          0%, 100% { opacity: 0.1; transform: scale(1); }
          50% { opacity: 0.2; transform: scale(1.05); }
        }
        @keyframes breathe {
          0%, 100% { transform: scale(1); }
          50% { transform: scale(1.05); }
        }
      `}</style>
    </div>
  );
};

export default Eclissi;

