### React Component Integration

```typescript
const LunaOrb = () => {
  const [orbState, setOrbState] = useState<OrbState>(DEFAULT_IDLE_STATE);
  const stateManager = useRef(new OrbStateManager());

  useEffect(() => {
    // WebSocket connection to Luna Engine
    const ws = new WebSocket('ws://localhost:8000/orb');

    ws.onmessage = (event) => {
      const command: OrbCommand = JSON.parse(event.data);

      switch(command.type) {
        case 'gesture':
          const gestureState = GESTURE_MAP[command.data.pattern];
          if (gestureState) stateManager.current.push(gestureState);
          break;
        case 'system_event':
          const systemState = detectFromSystem(command.data);
          stateManager.current.push(systemState);
          break;
        case 'state_change':
          stateManager.current.push(command.data);
          break;
      }

      setOrbState(stateManager.current.getCurrentState());
    };
  }, []);

  return <AnimatedOrb state={orbState} />;
};
```

